children.summary:
涵蓋連結串列的遍歷、刪除、插入、反轉、前後指標、快慢指標、雙指標、合併、分治及綜合應用，包含會員題與經典題型。

**C++ 模板（遍歷與反轉）**：

```cpp
// 遍歷連結串列
void traverse(ListNode* head) {
    for (ListNode* cur = head; cur; cur = cur->next) {
        // 處理 cur->val
    }
}

// 反轉連結串列（迭代）
ListNode* reverseList(ListNode* head) {
    ListNode* prev = nullptr;
    ListNode* curr = head;
    while (curr) {
        ListNode* next = curr->next;
        curr->next = prev;
        prev = curr;
        curr = next;
    }
    return prev;
}
```

涵蓋二叉樹的遍歷、DFS/BFS、LCA、直徑、BST、N叉樹、樹形DP、連結串列+二叉樹等，適合系統學習與刷題。

**C++ 模板（二叉樹 DFS）**：

```cpp
// 二叉樹 DFS（前序遍歷）
void dfs(TreeNode* root) {
    if (!root)
        return;
    // 處理 root->val（前序）
    dfs(root->left);
    dfs(root->right);
}

// 求二叉樹最大深度（後序遍歷）
int maxDepth(TreeNode* root) {
    if (!root)
        return 0;
    return max(maxDepth(root->left), maxDepth(root->right)) + 1;
}
```

二叉樹的遍歷是理解樹結構的基礎，主要有三種深度優先遍歷（DFS）方式：

**三種遍歷方式**：

1. **前序遍歷（Preorder）**：根 → 左 → 右
2. **中序遍歷（Inorder）**：左 → 根 → 右（對於二叉搜索樹，得到升序序列）
3. **後序遍歷（Postorder）**：左 → 右 → 根

**C++ 模板（遞迴）**：

```cpp
// 二叉樹節點定義
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

// 前序遍歷：根 → 左 → 右
void preorder(TreeNode* root, vector<int>& result) {
    if (!root) {
        return;
    }
    result.push_back(root->val); // 訪問根節點
    preorder(root->left, result);  // 遍歷左子樹
    preorder(root->right, result); // 遍歷右子樹
}

// 中序遍歷：左 → 根 → 右
void inorder(TreeNode* root, vector<int>& result) {
    if (!root) {
        return;
    }
    inorder(root->left, result);   // 遍歷左子樹
    result.push_back(root->val);  // 訪問根節點
    inorder(root->right, result);  // 遍歷右子樹
}

// 後序遍歷：左 → 右 → 根
void postorder(TreeNode* root, vector<int>& result) {
    if (!root) {
        return;
    }
    postorder(root->left, result);  // 遍歷左子樹
    postorder(root->right, result); // 遍歷右子樹
    result.push_back(root->val);   // 訪問根節點
}
```

**C++ 模板（迭代）**：

```cpp
// 前序遍歷（迭代）
vector<int> preorderIterative(TreeNode* root) {
    vector<int> result;
    if (!root) {
        return result;
    }
    stack<TreeNode*> stk;
    stk.push(root);
    while (!stk.empty()) {
        TreeNode* node = stk.top();
        stk.pop();
        result.push_back(node->val);
        // 先右後左，因為堆疊是 LIFO
        if (node->right) {
            stk.push(node->right);
        }
        if (node->left) {
            stk.push(node->left);
        }
    }
    return result;
}

// 中序遍歷（迭代）
vector<int> inorderIterative(TreeNode* root) {
    vector<int> result;
    stack<TreeNode*> stk;
    TreeNode* curr = root;
    while (curr || !stk.empty()) {
        // 一直向左走到底
        while (curr) {
            stk.push(curr);
            curr = curr->left;
        }
        curr = stk.top();
        stk.pop();
        result.push_back(curr->val);
        curr = curr->right; // 轉向右子樹
    }
    return result;
}

// 後序遍歷（迭代）
vector<int> postorderIterative(TreeNode* root) {
    vector<int> result;
    if (!root) {
        return result;
    }
    stack<TreeNode*> stk;
    TreeNode* prev = nullptr;
    TreeNode* curr = root;
    while (curr || !stk.empty()) {
        while (curr) {
            stk.push(curr);
            curr = curr->left;
        }
        curr = stk.top();
        // 右子樹為空或已訪問，訪問當前節點
        if (!curr->right || curr->right == prev) {
            result.push_back(curr->val);
            stk.pop();
            prev = curr;
            curr = nullptr;
        } else {
            curr = curr->right;
        }
    }
    return result;
}
```

自頂向下 DFS 從根節點開始，將信息從父節點傳遞給子節點，通常用於計算路徑和、深度、路徑條件等問題。

**核心思想**：
- 從根節點開始遞迴
- 在遞迴過程中累積信息（深度、路徑和、路徑等）
- 將信息作為參數傳遞給子節點
- 先序遍歷的順序：根 → 左 → 右

**C++ 模板**：

```cpp
// 自頂向下 DFS：計算最大深度
int maxDepth(TreeNode* root) {
    return dfs(root, 0);
}

int dfs(TreeNode* node, int depth) {
    if (!node) {
        return depth;
    }
    // 向下傳遞深度信息
    int left_depth = dfs(node->left, depth + 1);
    int right_depth = dfs(node->right, depth + 1);
    return max(left_depth, right_depth);
}

// 自頂向下 DFS：路徑和等於目標值
bool hasPathSum(TreeNode* root, int target_sum) {
    return dfsPathSum(root, 0, target_sum);
}

bool dfsPathSum(TreeNode* node, int current_sum, int target_sum) {
    if (!node) {
        return false;
    }
    current_sum += node->val;
    // 葉子節點判斷
    if (!node->left && !node->right) {
        return current_sum == target_sum;
    }
    // 向下傳遞當前路徑和
    return dfsPathSum(node->left, current_sum, target_sum) ||
           dfsPathSum(node->right, current_sum, target_sum);
}

// 自頂向下 DFS：記錄路徑
void findPaths(TreeNode* root, vector<vector<int>>& paths) {
    vector<int> path;
    dfsPath(root, path, paths);
}

void dfsPath(TreeNode* node, vector<int>& path, vector<vector<int>>& paths) {
    if (!node) {
        return;
    }
    path.push_back(node->val); // 記錄當前節點
    if (!node->left && !node->right) {
        paths.push_back(path); // 葉子節點，記錄完整路徑
    } else {
        dfsPath(node->left, path, paths);
        dfsPath(node->right, path, paths);
    }
    path.pop_back(); // 回溯，移除當前節點
}
```

自底向上 DFS 先遞迴處理子節點，再處理當前節點，將子節點的信息匯總到父節點。通常用於計算子樹信息、平衡判斷、最近公共祖先等問題。

**核心思想**：
- 先遞迴處理左右子樹
- 獲取左右子樹的返回值
- 基於子樹信息計算當前節點的結果
- 後序遍歷的順序：左 → 右 → 根

**C++ 模板**：

```cpp
// 自底向上 DFS：計算最大深度
int maxDepth(TreeNode* root) {
    if (!root) {
        return 0;
    }
    int leftDepth = maxDepth(root->left);   // 左子樹深度
    int rightDepth = maxDepth(root->right); // 右子樹深度
    return max(leftDepth, rightDepth) + 1;  // 當前深度 = 子樹最大深度 + 1
}

// 自底向上 DFS：判斷平衡二叉樹
bool isBalanced(TreeNode* root) {
    return getHeight(root) != -1;
}

int getHeight(TreeNode* node) {
    if (!node) {
        return 0;
    }
    int left_height = getHeight(node->left);
    if (left_height == -1) {
        return -1; // 左子樹不平衡
    }
    int right_height = getHeight(node->right);
    if (right_height == -1) {
        return -1; // 右子樹不平衡
    }
    // 左右子樹高度差超過 1，不平衡
    if (abs(left_height - right_height) > 1) {
        return -1;
    }
    return max(left_height, right_height) + 1;
}

// 自底向上 DFS：計算子樹節點數
int countNodes(TreeNode* root) {
    if (!root) {
        return 0;
    }
    int leftCount = countNodes(root->left);   // 左子樹節點數
    int rightCount = countNodes(root->right); // 右子樹節點數
    return leftCount + rightCount + 1;        // 總節點數 = 左 + 右 + 根
}

// 自底向上 DFS：判斷對稱二叉樹
bool isSymmetric(TreeNode* root) {
    return isMirror(root, root);
}

bool isMirror(TreeNode* left, TreeNode* right) {
    if (!left && !right) {
        return true;
    }
    if (!left || !right) {
        return false;
    }
    // 當前節點值相等 && 左的左 = 右的右 && 左的右 = 右的左
    return (left->val == right->val) &&
           isMirror(left->left, right->right) &&
           isMirror(left->right, right->left);
}
```

刪除二叉樹節點是一種特殊的自底向上 DFS，需要根據條件判斷是否保留當前節點，並處理子節點的刪除結果。

**核心思想**：
- 後序遍歷，先處理子節點
- 根據條件判斷是否刪除當前節點
- 返回新的子樹根節點（可能為 nullptr）

**C++ 模板**：

```cpp
// 刪除二叉搜索樹中的節點
TreeNode* deleteNode(TreeNode* root, int key) {
    if (!root) {
        return nullptr;
    }

    if (key < root->val) {
        root->left = deleteNode(root->left, key);   // 在左子樹中刪除
    } else if (key > root->val) {
        root->right = deleteNode(root->right, key); // 在右子樹中刪除
    } else {
        // 找到目標節點
        if (!root->left) {
            return root->right; // 無左子樹，用右子樹替代
        }
        if (!root->right) {
            return root->left;  // 無右子樹，用左子樹替代
        }
        // 有兩個子節點：找右子樹最小節點替代
        TreeNode* min_node = root->right;
        while (min_node->left) {
            min_node = min_node->left;
        }
        root->val = min_node->val; // 用後繼節點值替代
        root->right = deleteNode(root->right, min_node->val); // 刪除後繼節點
    }
    return root;
}

// 刪除葉子節點
TreeNode* removeLeafNodes(TreeNode* root, int target) {
    if (!root) {
        return nullptr;
    }
    // 先處理子節點
    root->left = removeLeafNodes(root->left, target);
    root->right = removeLeafNodes(root->right, target);

    // 如果當前節點是目標值的葉子節點，刪除
    if (!root->left && !root->right && root->val == target) {
        return nullptr;
    }
    return root;
}

// 修剪二叉搜索樹
TreeNode* trimBst(TreeNode* root, int low, int high) {
    if (!root) {
        return nullptr;
    }

    if (root->val < low) {
        return trimBst(root->right, low, high); // 當前節點太小，只保留右子樹
    }
    if (root->val > high) {
        return trimBst(root->left, low, high);  // 當前節點太大，只保留左子樹
    }

    // 當前節點在範圍內，遞迴修剪左右子樹
    root->left = trimBst(root->left, low, high);
    root->right = trimBst(root->right, low, high);
    return root;
}
```

「有遞有歸」是指在遞迴過程中，既要向下遞迴（遞），也要處理返回值（歸）。通常用於需要同時考慮自頂向下傳遞信息和自底向上匯總信息的問題。

**核心思想**：
- 遞：向下傳遞參數（路徑和、深度、父節點信息等）
- 歸：向上返回結果（子樹信息、是否滿足條件等）
- 結合兩者的優勢

**C++ 模板**：

```cpp
// 路徑總和 III：計算路徑和等於目標值的路徑數
int pathSum(TreeNode* root, int target_sum) {
    if (!root) {
        return 0;
    }
    // 以當前節點為起點的路徑數 + 左子樹路徑數 + 右子樹路徑數
    return dfsFrom(root, target_sum) +
           pathSum(root->left, target_sum) +
           pathSum(root->right, target_sum);
}

// 從當前節點開始，計算路徑和等於 target 的路徑數
long long dfsFrom(TreeNode* node, long long target) {
    if (!node) {
        return 0;
    }
    int count = (node->val == target) ? 1 : 0;
    // 繼續向下尋找
    count += dfsFrom(node->left, target - node->val);
    count += dfsFrom(node->right, target - node->val);
    return count;
}

// 二叉樹最大路徑和
int maxPathSum(TreeNode* root) {
    int max_sum = INT_MIN;
    dfsMaxPath(root, max_sum);
    return max_sum;
}

// 返回以當前節點為端點的最大路徑和
int dfsMaxPath(TreeNode* node, int& max_sum) {
    if (!node) {
        return 0;
    }
    // 遞：計算左右子樹的最大貢獻（負數則不選）
    int left_max = max(0, dfsMaxPath(node->left, max_sum));
    int right_max = max(0, dfsMaxPath(node->right, max_sum));

    // 歸：更新全局最大路徑和（可以同時包含左右子樹）
    max_sum = max(max_sum, node->val + left_max + right_max);

    // 返回以當前節點為端點的最大路徑和（只能選一側）
    return node->val + max(left_max, right_max);
}

// 相同節點值的最大路徑長度
int longestUnivaluePath(TreeNode* root) {
    int max_len = 0;
    dfsUnivalue(root, max_len);
    return max_len;
}

int dfsUnivalue(TreeNode* node, int& max_len) {
    if (!node) {
        return 0;
    }
    int left_len = dfsUnivalue(node->left, max_len);
    int right_len = dfsUnivalue(node->right, max_len);

    // 檢查左右子節點值是否與當前節點相同
    int left = (node->left && node->left->val == node->val) ? left_len + 1 : 0;
    int right = (node->right && node->right->val == node->val) ? right_len + 1 : 0;

    // 更新全局最大長度
    max_len = max(max_len, left + right);

    // 返回單側最大長度
    return max(left, right);
}
```

二叉樹的直徑是指樹中任意兩個節點之間最長路徑的邊數。這類問題通常使用自底向上 DFS，在計算高度的同時更新直徑。

**核心思想**：
- 直徑 = 某個節點的左子樹高度 + 右子樹高度
- 遍歷所有節點，計算每個節點的左右子樹高度
- 維護全局最大直徑

**C++ 模板**：

```cpp
// 二叉樹的直徑
int diameterOfBinaryTree(TreeNode* root) {
    int diameter = 0;
    dfsHeight(root, diameter);
    return diameter;
}

// 返回樹的高度，同時更新直徑
int dfsHeight(TreeNode* node, int& diameter) {
    if (!node) {
        return 0;
    }
    int leftHeight = dfsHeight(node->left, diameter);   // 左子樹高度
    int rightHeight = dfsHeight(node->right, diameter); // 右子樹高度

    // 更新直徑：左高度 + 右高度
    diameter = max(diameter, leftHeight + rightHeight);

    // 返回當前節點的高度
    return max(leftHeight, rightHeight) + 1;
}

// 邊權和最大的直徑
long long maxDiameterSum(TreeNode* root) {
    long long max_sum = 0;
    dfsMaxSum(root, max_sum);
    return max_sum;
}

pair<long long, int> dfsMaxSum(TreeNode* node, long long& max_sum) {
    if (!node) {
        return {0, 0}; // {路徑和, 高度}
    }

    auto [left_sum, left_h] = dfsMaxSum(node->left, max_sum);
    auto [right_sum, right_h] = dfsMaxSum(node->right, max_sum);

    // 當前節點為直徑中心時的路徑和
    long long current_sum = node->val + left_sum + right_sum;
    max_sum = max(max_sum, current_sum);

    // 返回通過當前節點的最大單側路徑
    long long max_side = node->val + max(left_sum, right_sum);
    int height = max(left_h, right_h) + 1;
    return {max_side, height};
}
```

二叉樹中的回溯通常用於尋找所有路徑、組合等問題。核心是在遞迴過程中記錄路徑，遞迴返回時恢復狀態。

**核心思想**：
- 選擇：將當前節點加入路徑
- 遞迴：繼續處理子節點
- 撤銷：回溯時移除當前節點

**C++ 模板**：

```cpp
// 所有從根到葉子的路徑
vector<string> binaryTreePaths(TreeNode* root) {
    vector<string> paths;
    if (!root) {
        return paths;
    }
    string path;
    dfsPath(root, path, paths);
    return paths;
}

void dfsPath(TreeNode* node, string& path, vector<string>& paths) {
    if (!node) {
        return;
    }

    int len = path.size(); // 記錄當前路徑長度，用於回溯
    path += to_string(node->val);

    if (!node->left && !node->right) {
        paths.push_back(path); // 葉子節點，記錄路徑
    } else {
        path += "->"; // 非葉子節點，添加箭頭
        dfsPath(node->left, path, paths);
        dfsPath(node->right, path, paths);
    }

    path.resize(len); // 回溯，恢復路徑
}

// 路徑總和 II：找出所有和為目標值的路徑
vector<vector<int>> pathSum(TreeNode* root, int target_sum) {
    vector<vector<int>> paths;
    vector<int> path;
    dfsPathSum(root, target_sum, path, paths);
    return paths;
}

void dfsPathSum(TreeNode* node, int target, vector<int>& path, vector<vector<int>>& paths) {
    if (!node) {
        return;
    }

    path.push_back(node->val); // 選擇當前節點

    if (!node->left && !node->right && target == node->val) {
        paths.push_back(path); // 找到一條路徑
    } else {
        dfsPathSum(node->left, target - node->val, path, paths);
        dfsPathSum(node->right, target - node->val, path, paths);
    }

    path.pop_back(); // 回溯，移除當前節點
}
```

最近公共祖先（LCA, Lowest Common Ancestor）是指兩個節點的最近共同祖先節點。

**核心思想**：
- 後序遍歷，從葉子向根匯報
- 如果當前節點是目標節點之一，返回當前節點
- 如果左右子樹都找到目標，當前節點是 LCA
- 如果只有一側找到，返回找到的那側

**C++ 模板**：

```cpp
// 二叉樹的最近公共祖先
TreeNode* lowestCommonAncestor(TreeNode* root, TreeNode* p, TreeNode* q) {
    if (!root || root == p || root == q) {
        return root; // 找到目標節點或到達空節點
    }

    TreeNode* left = lowestCommonAncestor(root->left, p, q);   // 左子樹搜索
    TreeNode* right = lowestCommonAncestor(root->right, p, q); // 右子樹搜索

    if (left && right) {
        return root; // 左右都找到，當前節點是 LCA
    }
    return left ? left : right; // 返回非空的一側
}

// 二叉搜索樹的最近公共祖先（利用 BST 性質）
TreeNode* lowestCommonAncestorBst(TreeNode* root, TreeNode* p, TreeNode* q) {
    if (!root) {
        return nullptr;
    }

    // p, q 都在左子樹
    if (p->val < root->val && q->val < root->val) {
        return lowestCommonAncestorBst(root->left, p, q);
    }
    // p, q 都在右子樹
    if (p->val > root->val && q->val > root->val) {
        return lowestCommonAncestorBst(root->right, p, q);
    }
    // 一個在左，一個在右，當前節點是 LCA
    return root;
}

// 帶父指標的最近公共祖先
TreeNode* lowestCommonAncestorWithParent(TreeNode* p, TreeNode* q) {
    unordered_set<TreeNode*> ancestors;

    // 記錄 p 的所有祖先
    TreeNode* node = p;
    while (node) {
        ancestors.insert(node);
        node = node->parent;
    }

    // 找 q 的第一個在 ancestors 中的祖先
    node = q;
    while (node) {
        if (ancestors.count(node)) {
            return node;
        }
        node = node->parent;
    }
    return nullptr;
}
```

二叉搜索樹（BST）滿足：左子樹所有節點值 < 根節點值 < 右子樹所有節點值。中序遍歷 BST 得到升序序列。

**核心性質**：
- 中序遍歷得到升序序列
- 查找、插入、刪除的平均時間複雜度 $O(\log n)$
- 可以利用性質優化搜索

**C++ 模板**：

```cpp
// BST 搜索
TreeNode* searchBst(TreeNode* root, int val) {
    if (!root || root->val == val) {
        return root;
    }
    return val < root->val ? searchBst(root->left, val) : searchBst(root->right, val);
}

// BST 插入
TreeNode* insertIntoBst(TreeNode* root, int val) {
    if (!root) {
        return new TreeNode(val);
    }
    if (val < root->val) {
        root->left = insertIntoBst(root->left, val);
    } else {
        root->right = insertIntoBst(root->right, val);
    }
    return root;
}

// 驗證二叉搜索樹
bool isValidBst(TreeNode* root) {
    return validate(root, LLONG_MIN, LLONG_MAX);
}

bool validate(TreeNode* node, long long min_val, long long max_val) {
    if (!node) {
        return true;
    }
    if (node->val <= min_val || node->val >= max_val) {
        return false;
    }
    return validate(node->left, min_val, node->val) &&
           validate(node->right, node->val, max_val);
}

// BST 中第 k 小的元素
int kthSmallest(TreeNode* root, int k) {
    int count = 0;
    int result = 0;
    inorder(root, k, count, result);
    return result;
}

void inorder(TreeNode* node, int k, int& count, int& result) {
    if (!node) {
        return;
    }
    inorder(node->left, k, count, result);
    count++;
    if (count == k) {
        result = node->val;
        return;
    }
    inorder(node->right, k, count, result);
}
```

從遍歷序列重建二叉樹，需要利用不同遍歷方式的性質。

**核心思想**：
- 前序：第一個元素是根
- 後序：最後一個元素是根  
- 中序：根左側是左子樹，右側是右子樹
- 需要兩種遍歷序列才能唯一確定

**C++ 模板**：

```cpp
// 從前序和中序遍歷序列構造二叉樹
TreeNode* buildTree(vector<int>& preorder, vector<int>& inorder) {
    unordered_map<int, int> in_map;
    for (int i = 0; i < inorder.size(); i++) {
        in_map[inorder[i]] = i; // 記錄中序位置
    }
    return build(preorder, 0, preorder.size() - 1,
                 inorder, 0, inorder.size() - 1, in_map);
}

TreeNode* build(vector<int>& preorder, int pre_start, int pre_end,
                vector<int>& inorder, int in_start, int in_end,
                unordered_map<int, int>& in_map) {
    if (pre_start > pre_end) {
        return nullptr;
    }

    int root_val = preorder[pre_start];
    TreeNode* root = new TreeNode(root_val);
    int in_root = in_map[root_val]; // 根在中序中的位置
    int left_size = in_root - in_start; // 左子樹大小

    root->left = build(preorder, pre_start + 1, pre_start + left_size,
                       inorder, in_start, in_root - 1, in_map);
    root->right = build(preorder, pre_start + left_size + 1, pre_end,
                        inorder, in_root + 1, in_end, in_map);
    return root;
}

// 從中序和後序遍歷序列構造二叉樹
TreeNode* buildTreeInPost(vector<int>& inorder, vector<int>& postorder) {
    unordered_map<int, int> in_map;
    for (int i = 0; i < inorder.size(); i++) {
        in_map[inorder[i]] = i;
    }
    return buildIp(inorder, 0, inorder.size() - 1,
                   postorder, 0, postorder.size() - 1, in_map);
}

TreeNode* buildIp(vector<int>& inorder, int in_start, int in_end,
                  vector<int>& postorder, int post_start, int post_end,
                  unordered_map<int, int>& in_map) {
    if (in_start > in_end) {
        return nullptr;
    }

    int root_val = postorder[post_end]; // 後序最後一個是根
    TreeNode* root = new TreeNode(root_val);
    int in_root = in_map[root_val];
    int left_size = in_root - in_start;

    root->left = buildIp(inorder, in_start, in_root - 1,
                         postorder, post_start, post_start + left_size - 1, in_map);
    root->right = buildIp(inorder, in_root + 1, in_end,
                          postorder, post_start + left_size, post_end - 1, in_map);
    return root;
}
```

二叉樹的插入和刪除操作，特別是在二叉搜索樹中。

**核心思想**：
- BST 插入：比較大小，遞迴插入到正確位置
- BST 刪除：分三種情況處理（無子節點、一個子節點、兩個子節點）

**C++ 模板**：

```cpp
// BST 插入節點
TreeNode* insertIntoBst(TreeNode* root, int val) {
    if (!root) {
        return new TreeNode(val);
    }
    if (val < root->val) {
        root->left = insertIntoBst(root->left, val);
    } else {
        root->right = insertIntoBst(root->right, val);
    }
    return root;
}

// BST 刪除節點
TreeNode* deleteNode(TreeNode* root, int key) {
    if (!root) {
        return nullptr;
    }

    if (key < root->val) {
        root->left = deleteNode(root->left, key);
    } else if (key > root->val) {
        root->right = deleteNode(root->right, key);
    } else {
        // 找到要刪除的節點
        if (!root->left) {
            return root->right; // 情況 1：無左子節點
        }
        if (!root->right) {
            return root->left;  // 情況 2：無右子節點
        }
        // 情況 3：有兩個子節點，找右子樹最小節點
        TreeNode* min_node = root->right;
        while (min_node->left) {
            min_node = min_node->left;
        }
        root->val = min_node->val; // 用後繼值替換
        root->right = deleteNode(root->right, min_node->val); // 刪除後繼
    }
    return root;
}

// 找到 BST 中的最小節點
TreeNode* findMin(TreeNode* root) {
    while (root && root->left) {
        root = root->left;
    }
    return root;
}

// 找到 BST 中的最大節點
TreeNode* findMax(TreeNode* root) {
    while (root && root->right) {
        root = root->right;
    }
    return root;
}
```

樹形 DP 是在樹結構上進行動態規劃，通常定義 `dp[node][state]` 表示以 `node` 為根的子樹在某種狀態下的最優解。

**核心思想**：
- 後序遍歷，從葉子到根
- 定義狀態（選/不選、顏色、狀態等）
- 從子節點狀態轉移到父節點

**C++ 模板**：

```cpp
// 打家劫舍 III：樹形 DP
int rob(TreeNode* root) {
    auto [rob_root, not_rob_root] = dfsRob(root);
    return max(rob_root, not_rob_root);
}

// 返回 {搶當前節點的最大金額, 不搶當前節點的最大金額}
pair<int, int> dfsRob(TreeNode* node) {
    if (!node) {
        return {0, 0};
    }

    auto [rob_left, not_rob_left] = dfsRob(node->left);
    auto [rob_right, not_rob_right] = dfsRob(node->right);

    // 搶當前節點：不能搶子節點
    int rob = node->val + not_rob_left + not_rob_right;
    // 不搶當前節點：子節點可搶可不搶
    int not_rob = max(rob_left, not_rob_left) + max(rob_right, not_rob_right);

    return {rob, not_rob};
}

// 二叉樹染色：相鄰節點顏色不同
int minCost(TreeNode* root, vector<int>& cost) {
    // dp[node][color] = 以 node 為根，node 染成 color 的最小成本
    return min({dfsColor(root, 0, cost),
                dfsColor(root, 1, cost),
                dfsColor(root, 2, cost)});
}

int dfsColor(TreeNode* node, int color, vector<int>& cost) {
    if (!node) {
        return 0;
    }

    int minCost = cost[color];

    // 左子節點選擇不同顏色的最小成本
    int left_min = INT_MAX;
    for (int c = 0; c < 3; c++) {
        if (c != color) {
            left_min = min(left_min, dfsColor(node->left, c, cost));
        }
    }

    // 右子節點選擇不同顏色的最小成本
    int right_min = INT_MAX;
    for (int c = 0; c < 3; c++) {
        if (c != color) {
            right_min = min(right_min, dfsColor(node->right, c, cost));
        }
    }

    return minCost + (left_min == INT_MAX ? 0 : left_min) + (right_min == INT_MAX ? 0 : right_min);
}
```

二叉樹的層序遍歷（BFS）使用佇列實現，按層從左到右訪問節點。

**核心思想**：
- 使用佇列保存每一層的節點
- 逐層處理，從左到右
- 可以記錄層數、層大小等信息

**C++ 模板**：

```cpp
// 層序遍歷
vector<vector<int>> levelOrder(TreeNode* root) {
    vector<vector<int>> result;
    if (!root) {
        return result;
    }

    queue<TreeNode*> q;
    q.push(root);

    while (!q.empty()) {
        int level_size = q.size();
        vector<int> current_level;

        for (int i = 0; i < level_size; i++) {
            TreeNode* node = q.front();
            q.pop();
            current_level.push_back(node->val);

            if (node->left) {
                q.push(node->left);
            }
            if (node->right) {
                q.push(node->right);
            }
        }
        result.push_back(current_level);
    }
    return result;
}

// 鋸齒形層序遍歷
vector<vector<int>> zigzagLevelOrder(TreeNode* root) {
    vector<vector<int>> result;
    if (!root) {
        return result;
    }

    queue<TreeNode*> q;
    q.push(root);
    bool left_to_right = true;

    while (!q.empty()) {
        int level_size = q.size();
        vector<int> current_level(level_size);

        for (int i = 0; i < level_size; i++) {
            TreeNode* node = q.front();
            q.pop();

            // 根據方向決定插入位置
            int index = left_to_right ? i : (level_size - 1 - i);
            current_level[index] = node->val;

            if (node->left) {
                q.push(node->left);
            }
            if (node->right) {
                q.push(node->right);
            }
        }
        result.push_back(current_level);
        left_to_right = !left_to_right; // 切換方向
    }
    return result;
}

// 每層的最大值
vector<int> largestValues(TreeNode* root) {
    vector<int> result;
    if (!root) {
        return result;
    }

    queue<TreeNode*> q;
    q.push(root);

    while (!q.empty()) {
        int level_size = q.size();
        int max_val = INT_MIN;

        for (int i = 0; i < level_size; i++) {
            TreeNode* node = q.front();
            q.pop();
            max_val = max(max_val, node->val);

            if (node->left) {
                q.push(node->left);
            }
            if (node->right) {
                q.push(node->right);
            }
        }
        result.push_back(max_val);
    }
    return result;
}

// 右視圖
vector<int> rightSideView(TreeNode* root) {
    vector<int> result;
    if (!root) {
        return result;
    }

    queue<TreeNode*> q;
    q.push(root);

    while (!q.empty()) {
        int level_size = q.size();

        for (int i = 0; i < level_size; i++) {
            TreeNode* node = q.front();
            q.pop();

            // 每層最後一個節點
            if (i == level_size - 1) {
                result.push_back(node->val);
            }

            if (node->left) {
                q.push(node->left);
            }
            if (node->right) {
                q.push(node->right);
            }
        }
    }
    return result;
}
```

涵蓋一般樹的遍歷、DFS、LCA、直徑、拓撲排序、時間戳、點分治等，適合進階學習。

**C++ 模板（一般樹 DFS）**：

```cpp
// 一般樹 DFS（鄰接表）
void dfs(int u, int fa, vector<vector<int>>& adj) {
    // 處理節點 u
    for (int v : adj[u]) {
        if (v != fa) {
            dfs(v, u, adj);
        }
    }
}
```

DFS 時間戳記錄每個節點的訪問時間（`in-time`）和離開時間（`out-time`），常用於判斷祖先-後代關係、子樹查詢等問題。

**核心思想**：
- 在 DFS 過程中記錄進入節點的時間 `in[u]` 和離開節點的時間 `out[u]`
- 節點 $u$ 是節點 $v$ 的祖先 $\iff$ `in[u] <= in[v] && out[v] <= out[u]`
- `u` 的子樹對應時間區間 `[in[u], out[u]]`
- 可以將樹上問題轉化為序列問題

**時間戳性質**：

1. **祖先-後代關係**：$u$ 是 $v$ 的祖先 $\iff$ `in[u] < in[v] < out[v] < out[u]`
2. **子樹區間**：u 的子樹中所有節點的 in-time 在區間 `[in[u], out[u]]` 內
3. **DFS 序**：按 in-time 排序得到 DFS 序列
4. **歐拉序**：DFS 過程中每次訪問節點都記錄，得到歐拉序列

**應用場景**：
- 判斷祖先-後代關係：$O(1)$ 時間
- 子樹查詢：將子樹問題轉化為區間問題，配合線段樹、樹狀陣列等
- LCA 問題：配合 RMQ 算法
- 樹上差分：利用時間戳將樹上路徑轉化為序列操作

**C++ 模板**：

```cpp
// DFS 時間戳
class DfsTimestamp {
public:
    vector<int> in_time;   // 進入時間
    vector<int> out_time;  // 離開時間
    vector<vector<int>> adj; // 鄰接表
    int timer;

    DfsTimestamp(int n) : in_time(n), out_time(n), adj(n), timer(0) {}

    void addEdge(int u, int v) {
        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    void dfs(int u, int parent) {
        in_time[u] = timer++;  // 記錄進入時間

        for (int v : adj[u]) {
            if (v != parent) {
                dfs(v, u);
            }
        }

        out_time[u] = timer++; // 記錄離開時間
    }

    // 判斷 u 是否是 v 的祖先
    bool isAncestor(int u, int v) {
        return in_time[u] <= in_time[v] && out_time[v] <= out_time[u];
    }

    // 獲取 u 的子樹對應的時間區間
    pair<int, int> getSubtreeRange(int u) {
        return {in_time[u], out_time[u]};
    }
};

// 歐拉序（用於 LCA）
class EulerTour {
public:
    vector<int> euler;     // 歐拉序列
    vector<int> first;     // 節點首次出現位置
    vector<int> depth;     // 節點深度
    vector<vector<int>> adj;

    EulerTour(int n) : first(n, -1), adj(n) {}

    void addEdge(int u, int v) {
        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    void dfs(int u, int parent, int d) {
        first[u] = euler.size();
        euler.push_back(u);
        depth.push_back(d);

        for (int v : adj[u]) {
            if (v != parent) {
                dfs(v, u, d + 1);
                euler.push_back(u); // 回到 u 時再次記錄
                depth.push_back(d);
            }
        }
    }

    void build(int root) {
        dfs(root, -1, 0);
    }
};

// 樹上差分（配合時間戳）
class TreeDifference {
public:
    vector<int> diff;      // 差分陣列
    vector<int> in_time;
    vector<vector<int>> adj;
    int timer;

    TreeDifference(int n) : diff(n * 2), in_time(n), adj(n), timer(0) {}

    void dfs(int u, int parent) {
        in_time[u] = timer++;
        for (int v : adj[u]) {
            if (v != parent) {
                dfs(v, u);
            }
        }
    }

    // 將子樹 u 中所有節點加上 val
    void addSubtree(int u, int val) {
        diff[in_time[u]] += val;
        diff[in_time[u] + 1] -= val; // 區間加法
    }

    // 計算實際值
    vector<int> calculate(int n) {
        vector<int> result(n);
        int sum = 0;
        for (int i = 0; i < n; i++) {
            sum += diff[i];
            result[i] = sum;
        }
        return result;
    }
};
```

