最近公共祖先（LCA）與倍增演算法。倍增法預處理每個節點的第 $2^k$ 個祖先，查詢時間 $O(\log n)$。

**C++ 模板（倍增 LCA）**：

```cpp
const int kLog = 20;
int up[200005][kLog], depth[200005];  // up[u][j] = u 的第 2^j 個祖先

// DFS 預處理：計算每個節點的深度和祖先
void dfs(int u, int fa, vector<vector<int>>& adj) {
    up[u][0] = fa;  // 第 2^0 = 1 個祖先就是父節點
    // 倍增：計算第 2^j 個祖先
    for (int j = 1; j < kLog; j++) {
        up[u][j] = up[up[u][j - 1]][j - 1];
    }
    // 遍歷子節點
    for (int v : adj[u]) {
        if (v != fa) {
            depth[v] = depth[u] + 1;
            dfs(v, u, adj);
        }
    }
}

// 查詢 LCA：找到 u 和 v 的最近公共祖先
int lca(int u, int v) {
    // 讓 u 成為深度較大的節點
    if (depth[u] < depth[v]) {
        swap(u, v);
    }
    // 將 u 向上跳到與 v 同一深度
    int diff = depth[u] - depth[v];
    for (int j = 0; j < kLog; j++) {
        if ((diff >> j) & 1) {
            u = up[u][j];
        }
    }
    // 如果 u 和 v 已經相同，直接返回
    if (u == v) {
        return u;
    }
    // 同時向上跳，直到跳到 LCA 的下一層
    for (int j = kLog - 1; j >= 0; j--) {
        if (up[u][j] != up[v][j]) {
            u = up[u][j];
            v = up[v][j];
        }
    }
    return up[u][0];  // 返回 LCA（u 的父節點）
}
```

重心分解（點分治），用於統計樹上路徑相關問題，複雜度 $O(n \log n)$。

**C++ 模板（點分治）**：

```cpp
int sz[200005], mx_sub[200005], root, total;  // sz: 子樹大小, mx_sub: 最大子樹大小
bool removed[200005];  // 標記節點是否已被移除

// 計算子樹大小並找重心
void getSize(int u, int fa, vector<vector<int>>& adj) {
    sz[u] = 1;  // 初始化當前節點大小為 1
    mx_sub[u] = 0;  // 初始化最大子樹大小為 0
    // 遍歷所有子節點
    for (int v : adj[u]) {
        if (v != fa && !removed[v]) {
            getSize(v, u, adj);
            sz[u] += sz[v];  // 累加子樹大小
            mx_sub[u] = max(mx_sub[u], sz[v]);  // 更新最大子樹大小
        }
    }
    // 考慮父節點方向的子樹大小
    mx_sub[u] = max(mx_sub[u], total - sz[u]);
    // 更新重心：選擇最大子樹最小的節點
    if (mx_sub[u] < mx_sub[root]) {
        root = u;
    }
}

// 點分治主函數
void solve(int u, vector<vector<int>>& adj) {
    removed[u] = true;  // 標記當前重心已處理
    // 處理以 u 為重心的所有路徑
    for (int v : adj[u]) {
        if (!removed[v]) {
            total = sz[v];  // 設定當前子樹的總節點數
            root = 0;
            mx_sub[0] = INT_MAX;
            getSize(v, u, adj);  // 找到子樹的重心
            solve(root, adj);  // 遞迴處理子樹
        }
    }
}
```

涵蓋回溯的入門、子集、劃分、組合、排列、有重複元素、搜尋與折半列舉，適合系統學習。

**C++ 模板（回溯框架）**：

```cpp
// 回溯框架（子集型：選或不選）
vector<vector<int>> result;
vector<int> path;
void backtrack(vector<int>& nums, int i) {
    if (i == (int)nums.size()) {
        result.push_back(path);
        return;
    }
    // 不選 nums[i]
    backtrack(nums, i + 1);
    // 選 nums[i]
    path.push_back(nums[i]);
    backtrack(nums, i + 1);
    path.pop_back(); // 回溯
}
```

回溯是一種通過枚舉所有可能解來尋找問題解的算法，核心思想是「試錯」：嘗試一個選擇，如果不行就撤銷，再嘗試下一個。

**核心框架**：

```cpp
void backtrack(狀態, 路徑, 結果) {
    if (滿足結束條件) {
        結果.add(路徑);
        return;
    }

    for (選擇 in 選擇列表) {
        做選擇;           // 修改狀態
        backtrack(新狀態, 路徑, 結果);
        撤銷選擇;         // 恢復狀態（回溯）
    }
}
```

**回溯三要素**：
1. **路徑**：已經做出的選擇
2. **選擇列表**：當前可以做的選擇
3. **結束條件**：到達決策樹底層，無法再做選擇

**C++ 模板**：

```cpp
// 基礎回溯模板
class Solution {
    vector<vector<int>> result;
    vector<int> path;

public:
    void backtrack(int start, 其他參數) {
        // 結束條件
        if (滿足條件) {
            result.push_back(path);
            return;
        }

        // 枚舉選擇
        for (int i = start; i < n; i++) {
            // 剪枝（可選）
            if (不滿足條件) {
                continue;
            }

            // 做選擇
            path.push_back(i);

            // 遞迴
            backtrack(i + 1, 其他參數);

            // 撤銷選擇（回溯）
            path.pop_back();
        }
    }
};

// N 皇后問題（經典回溯）
class NQueens {
    vector<vector<string>> result;
    vector<string> board;
    int n;

public:
    vector<vector<string>> solveNQueens(int n) {
        this->n = n;
        board = vector<string>(n, string(n, '.'));
        backtrack(0);
        return result;
    }

private:
    void backtrack(int row) {
        if (row == n) {
            result.push_back(board);
            return;
        }

        for (int col = 0; col < n; col++) {
            if (!isValid(row, col)) {
                continue; // 剪枝
            }

            board[row][col] = 'Q';      // 做選擇
            backtrack(row + 1);         // 遞迴下一行
            board[row][col] = '.';      // 撤銷選擇
        }
    }

    bool isValid(int row, int col) {
        // 檢查列
        for (int i = 0; i < row; i++) {
            if (board[i][col] == 'Q') {
                return false;
            }
        }

        // 檢查左上對角線
        for (int i = row - 1, j = col - 1; i >= 0 && j >= 0; i--, j--) {
            if (board[i][j] == 'Q') {
                return false;
            }
        }

        // 檢查右上對角線
        for (int i = row - 1, j = col + 1; i >= 0 && j < n; i--, j++) {
            if (board[i][j] == 'Q') {
                return false;
            }
        }

        return true;
    }
};

// 解數獨（複雜回溯）
class Sudoku {
public:
    void solveSudoku(vector<vector<char>>& board) {
        backtrack(board, 0, 0);
    }

private:
    bool backtrack(vector<vector<char>>& board, int row, int col) {
        // 到達最後一行，找到解
        if (row == 9) {
            return true;
        }

        // 到達行末，換行
        if (col == 9) {
            return backtrack(board, row + 1, 0);
        }

        // 已填數字，跳過
        if (board[row][col] != '.') {
            return backtrack(board, row, col + 1);
        }

        // 嘗試填入 1-9
        for (char ch = '1'; ch <= '9'; ch++) {
            if (!isValid(board, row, col, ch)) {
                continue;
            }

            board[row][col] = ch;              // 做選擇
            if (backtrack(board, row, col + 1)) {
                return true;                    // 找到解
            }
            board[row][col] = '.';             // 撤銷選擇
        }

        return false; // 無解
    }

    bool isValid(vector<vector<char>>& board, int row, int col, char ch) {
        for (int i = 0; i < 9; i++) {
            if (board[row][i] == ch) return false; // 檢查行
            if (board[i][col] == ch) return false; // 檢查列

            // 檢查 3x3 宮格
            int box_row = (row / 3) * 3 + i / 3;
            int box_col = (col / 3) * 3 + i % 3;
            if (board[box_row][box_col] == ch) return false;
        }
        return true;
    }
};
```

子集型回溯用於生成集合的所有子集，每個元素可以選或不選。時間複雜度 $O(2^n)$。

**核心思想**：
- 對於每個元素，有「選」和「不選」兩種選擇
- 枚舉所有 $2^n$ 種可能
- 可以用二進制位表示選擇狀態

**C++ 模板**：

```cpp
// 子集 I（無重複元素）
class Subsets {
    vector<vector<int>> result;
    vector<int> path;

public:
    vector<vector<int>> subsets(vector<int>& nums) {
        backtrack(nums, 0);
        return result;
    }

private:
    void backtrack(vector<int>& nums, int start) {
        result.push_back(path); // 每個狀態都是一個子集

        for (int i = start; i < nums.size(); i++) {
            path.push_back(nums[i]);     // 選擇 nums[i]
            backtrack(nums, i + 1);      // 遞迴
            path.pop_back();             // 不選 nums[i]
        }
    }
};

// 子集 II（有重複元素）
class SubsetsWithDup {
    vector<vector<int>> result;
    vector<int> path;

public:
    vector<vector<int>> subsetsWithDup(vector<int>& nums) {
        sort(nums.begin(), nums.end()); // 排序以便去重
        backtrack(nums, 0);
        return result;
    }

private:
    void backtrack(vector<int>& nums, int start) {
        result.push_back(path);

        for (int i = start; i < nums.size(); i++) {
            // 去重：跳過同層重複元素
            if (i > start && nums[i] == nums[i - 1]) {
                continue;
            }

            path.push_back(nums[i]);
            backtrack(nums, i + 1);
            path.pop_back();
        }
    }
};

// 位運算枚舉子集
vector<vector<int>> subsetsIterative(vector<int>& nums) {
    vector<vector<int>> result;
    int n = nums.size();

    // 枚舉 0 到 2^n - 1
    for (int mask = 0; mask < (1 << n); mask++) {
        vector<int> subset;
        for (int i = 0; i < n; i++) {
            if (mask & (1 << i)) {  // 第 i 位為 1，選擇 nums[i]
                subset.push_back(nums[i]);
            }
        }
        result.push_back(subset);
    }
    return result;
}

// 電話號碼的字母組合
class LetterCombinations {
    vector<string> result;
    string path;
    vector<string> mapping = {"", "", "abc", "def", "ghi", "jkl", "mno", "pqrs", "tuv", "wxyz"};

public:
    vector<string> letterCombinations(string digits) {
        if (digits.empty()) {
            return result;
        }
        backtrack(digits, 0);
        return result;
    }

private:
    void backtrack(string& digits, int index) {
        if (index == digits.size()) {
            result.push_back(path);
            return;
        }

        string letters = mapping[digits[index] - '0'];
        for (char ch : letters) {
            path.push_back(ch);      // 選擇字母
            backtrack(digits, index + 1);
            path.pop_back();         // 回溯
        }
    }
};
```

劃分型回溯將字串或陣列劃分為若干部分，每部分滿足某種條件。通常枚舉劃分點，檢查每段是否合法。

**核心思想**：
- 枚舉所有可能的劃分方式
- 檢查每段是否滿足條件
- 記錄合法的劃分方案

**C++ 模板**：

```cpp
// 分割回文串
class PalindromePartitioning {
    vector<vector<string>> result;
    vector<string> path;

public:
    vector<vector<string>> partition(string s) {
        backtrack(s, 0);
        return result;
    }

private:
    void backtrack(string& s, int start) {
        if (start == s.size()) {
            result.push_back(path);
            return;
        }

        // 枚舉劃分點
        for (int i = start; i < s.size(); i++) {
            if (!isPalindrome(s, start, i)) {
                continue; // 不是迴文，剪枝
            }

            path.push_back(s.substr(start, i - start + 1)); // 添加當前回文串
            backtrack(s, i + 1);                            // 遞迴處理剩餘部分
            path.pop_back();                                // 回溯
        }
    }

    bool isPalindrome(string& s, int left, int right) {
        while (left < right) {
            if (s[left++] != s[right--]) {
                return false;
            }
        }
        return true;
    }
};

// 復原 IP 地址
class RestoreIpAddresses {
    vector<string> result;
    vector<string> path;

public:
    vector<string> restoreIpAddresses(string s) {
        backtrack(s, 0);
        return result;
    }

private:
    void backtrack(string& s, int start) {
        // 已有 4 段，檢查是否用完所有字符
        if (path.size() == 4) {
            if (start == s.size()) {
                result.push_back(path[0] + "." + path[1] + "." + path[2] + "." + path[3]);
            }
            return;
        }

        // 枚舉當前段的長度（1-3 位）
        for (int len = 1; len <= 3 && start + len <= s.size(); len++) {
            string segment = s.substr(start, len);

            // 檢查是否合法
            if (!isValid(segment)) {
                continue;
            }

            path.push_back(segment);
            backtrack(s, start + len);
            path.pop_back();
        }
    }

    bool isValid(string& segment) {
        // 前導零
        if (segment.size() > 1 && segment[0] == '0') {
            return false;
        }
        // 範圍檢查
        int num = stoi(segment);
        return num >= 0 && num <= 255;
    }
};

// 單詞拆分 II（回溯 + 記憶化）
class WordBreak {
    unordered_set<string> word_set;
    unordered_map<int, vector<string>> memo;

public:
    vector<string> wordBreak(string s, vector<string>& word_dict) {
        word_set = unordered_set<string>(word_dict.begin(), word_dict.end());
        return backtrack(s, 0);
    }

private:
    vector<string> backtrack(string& s, int start) {
        if (memo.count(start)) {
            return memo[start];
        }

        vector<string> result;

        if (start == s.size()) {
            result.push_back("");
            return result;
        }

        for (int end = start + 1; end <= s.size(); end++) {
            string word = s.substr(start, end - start);
            if (!word_set.count(word)) {
                continue;
            }

            vector<string> sub_results = backtrack(s, end);
            for (string& sub : sub_results) {
                result.push_back(word + (sub.empty() ? "" : " " + sub));
            }
        }

        memo[start] = result;
        return result;
    }
};
```

組合型回溯從 n 個元素中選 k 個，不考慮順序。時間複雜度 $O(C(n,k))$。

**核心思想**：
- 枚舉所有 k 元組合
- 保證組閤中元素有序（避免重複）
- 可以剪枝優化

**C++ 模板**：

```cpp
// 組合
class Combination {
    vector<vector<int>> result;
    vector<int> path;

public:
    vector<vector<int>> combine(int n, int k) {
        backtrack(n, k, 1);
        return result;
    }

private:
    void backtrack(int n, int k, int start) {
        // 剪枝：剩餘元素不足
        if (path.size() + (n - start + 1) < k) {
            return;
        }

        if (path.size() == k) {
            result.push_back(path);
            return;
        }

        for (int i = start; i <= n; i++) {
            path.push_back(i);
            backtrack(n, k, i + 1);
            path.pop_back();
        }
    }
};

// 組合總和（元素可重複使用）
class CombinationSum {
    vector<vector<int>> result;
    vector<int> path;

public:
    vector<vector<int>> combinationSum(vector<int>& candidates, int target) {
        backtrack(candidates, target, 0, 0);
        return result;
    }

private:
    void backtrack(vector<int>& candidates, int target, int sum, int start) {
        if (sum == target) {
            result.push_back(path);
            return;
        }

        if (sum > target) {
            return; // 剪枝
        }

        for (int i = start; i < candidates.size(); i++) {
            path.push_back(candidates[i]);
            // 可以重複使用，所以是 i 而不是 i+1
            backtrack(candidates, target, sum + candidates[i], i);
            path.pop_back();
        }
    }
};

// 組合總和 II（每個元素只能用一次，有重複元素）
class CombinationSum2 {
    vector<vector<int>> result;
    vector<int> path;

public:
    vector<vector<int>> combinationSum2(vector<int>& candidates, int target) {
        sort(candidates.begin(), candidates.end());
        backtrack(candidates, target, 0, 0);
        return result;
    }

private:
    void backtrack(vector<int>& candidates, int target, int sum, int start) {
        if (sum == target) {
            result.push_back(path);
            return;
        }

        for (int i = start; i < candidates.size(); i++) {
            // 剪枝
            if (sum + candidates[i] > target) {
                break;
            }

            // 去重：跳過同層重複元素
            if (i > start && candidates[i] == candidates[i - 1]) {
                continue;
            }

            path.push_back(candidates[i]);
            backtrack(candidates, target, sum + candidates[i], i + 1);
            path.pop_back();
        }
    }
};

// 組合總和 III
class CombinationSum3 {
    vector<vector<int>> result;
    vector<int> path;

public:
    vector<vector<int>> combinationSum3(int k, int n) {
        backtrack(k, n, 1, 0);
        return result;
    }

private:
    void backtrack(int k, int target, int start, int sum) {
        // 剪枝
        if (path.size() + (9 - start + 1) < k || sum > target) {
            return;
        }

        if (path.size() == k) {
            if (sum == target) {
                result.push_back(path);
            }
            return;
        }

        for (int i = start; i <= 9; i++) {
            path.push_back(i);
            backtrack(k, target, i + 1, sum + i);
            path.pop_back();
        }
    }
};
```

排列型回溯生成所有排列，考慮元素順序。時間複雜度 $O(n!)$。

**核心思想**：
- 枚舉所有 n! 種排列
- 使用 visited 陣列標記已選元素
- 或者通過交換元素實現

**C++ 模板**：

```cpp
// 全排列（無重複元素）
class Permute {
    vector<vector<int>> result;
    vector<int> path;
    vector<bool> used;

public:
    vector<vector<int>> permute(vector<int>& nums) {
        used.resize(nums.size(), false);
        backtrack(nums);
        return result;
    }

private:
    void backtrack(vector<int>& nums) {
        if (path.size() == nums.size()) {
            result.push_back(path);
            return;
        }

        for (int i = 0; i < nums.size(); i++) {
            if (used[i]) {
                continue; // 已使用，跳過
            }

            path.push_back(nums[i]);
            used[i] = true;           // 標記已使用
            backtrack(nums);
            used[i] = false;          // 恢復
            path.pop_back();
        }
    }
};

// 全排列 II（有重複元素）
class PermuteUnique {
    vector<vector<int>> result;
    vector<int> path;
    vector<bool> used;

public:
    vector<vector<int>> permuteUnique(vector<int>& nums) {
        sort(nums.begin(), nums.end()); // 排序以便去重
        used.resize(nums.size(), false);
        backtrack(nums);
        return result;
    }

private:
    void backtrack(vector<int>& nums) {
        if (path.size() == nums.size()) {
            result.push_back(path);
            return;
        }

        for (int i = 0; i < nums.size(); i++) {
            if (used[i]) {
                continue;
            }

            // 去重：如果當前元素與前一個相同，且前一個未使用，跳過
            if (i > 0 && nums[i] == nums[i - 1] && !used[i - 1]) {
                continue;
            }

            path.push_back(nums[i]);
            used[i] = true;
            backtrack(nums);
            used[i] = false;
            path.pop_back();
        }
    }
};

// 排列（交換法）
class PermuteSwap {
    vector<vector<int>> result;

public:
    vector<vector<int>> permute(vector<int>& nums) {
        backtrack(nums, 0);
        return result;
    }

private:
    void backtrack(vector<int>& nums, int start) {
        if (start == nums.size()) {
            result.push_back(nums);
            return;
        }

        for (int i = start; i < nums.size(); i++) {
            swap(nums[start], nums[i]);  // 選擇 nums[i] 作為第 start 個元素
            backtrack(nums, start + 1);
            swap(nums[start], nums[i]);  // 恢復
        }
    }
};

// 下一個排列（STL）
void nextPermutation(vector<int>& nums) {
    int n = nums.size();
    int i = n - 2;

    // 從後向前找第一個相鄰升序對 (i, i+1)
    while (i >= 0 && nums[i] >= nums[i + 1]) {
        i--;
    }

    if (i >= 0) {
        // 從後向前找第一個大於 nums[i] 的元素
        int j = n - 1;
        while (j >= 0 && nums[j] <= nums[i]) {
            j--;
        }
        swap(nums[i], nums[j]);
    }

    // 反轉 i+1 之後的部分
    reverse(nums.begin() + i + 1, nums.end());
}

// 第 k 個排列
string getPermutation(int n, int k) {
    vector<int> factorial(n);
    vector<int> nums;

    // 計算階乘
    factorial[0] = 1;
    for (int i = 1; i < n; i++) {
        factorial[i] = factorial[i - 1] * i;
    }

    // 初始化數字列表
    for (int i = 1; i <= n; i++) {
        nums.push_back(i);
    }

    k--; // 轉為 0-indexed
    string result;

    for (int i = n; i > 0; i--) {
        int index = k / factorial[i - 1];
        result += to_string(nums[index]);
        nums.erase(nums.begin() + index);
        k %= factorial[i - 1];
    }

    return result;
}
```

處理有重複元素的回溯問題，需要特別注意去重策略。

**核心思想**：
- 先排序，使相同元素相鄰
- 在同一層中跳過重複元素
- 區分「同層」和「同枝」的重複

**去重策略**：

1. **同層去重**：`if (i > start && nums[i] == nums[i-1]) continue;`
2. **同枝去重**：使用 used 陣列，`if (i > 0 && nums[i] == nums[i-1] && !used[i-1]) continue;`

**C++ 模板**：

```cpp
// 子集 II（有重複元素）
class SubsetsWithDup {
    vector<vector<int>> result;
    vector<int> path;

public:
    vector<vector<int>> subsetsWithDup(vector<int>& nums) {
        sort(nums.begin(), nums.end()); // 排序
        backtrack(nums, 0);
        return result;
    }

private:
    void backtrack(vector<int>& nums, int start) {
        result.push_back(path);

        for (int i = start; i < nums.size(); i++) {
            // 同層去重：跳過重複元素
            if (i > start && nums[i] == nums[i - 1]) {
                continue;
            }

            path.push_back(nums[i]);
            backtrack(nums, i + 1);
            path.pop_back();
        }
    }
};

// 組合總和 II（每個元素只能用一次）
class CombinationSum2 {
    vector<vector<int>> result;
    vector<int> path;

public:
    vector<vector<int>> combinationSum2(vector<int>& candidates, int target) {
        sort(candidates.begin(), candidates.end());
        backtrack(candidates, target, 0, 0);
        return result;
    }

private:
    void backtrack(vector<int>& candidates, int target, int sum, int start) {
        if (sum == target) {
            result.push_back(path);
            return;
        }

        for (int i = start; i < candidates.size(); i++) {
            if (sum + candidates[i] > target) {
                break; // 剪枝
            }

            // 同層去重
            if (i > start && candidates[i] == candidates[i - 1]) {
                continue;
            }

            path.push_back(candidates[i]);
            backtrack(candidates, target, sum + candidates[i], i + 1);
            path.pop_back();
        }
    }
};

// 全排列 II（有重複元素）
class PermuteUnique {
    vector<vector<int>> result;
    vector<int> path;
    vector<bool> used;

public:
    vector<vector<int>> permuteUnique(vector<int>& nums) {
        sort(nums.begin(), nums.end());
        used.resize(nums.size(), false);
        backtrack(nums);
        return result;
    }

private:
    void backtrack(vector<int>& nums) {
        if (path.size() == nums.size()) {
            result.push_back(path);
            return;
        }

        for (int i = 0; i < nums.size(); i++) {
            if (used[i]) {
                continue;
            }

            // 去重：如果當前元素與前一個相同，且前一個未使用
            // 說明在同一層，跳過
            if (i > 0 && nums[i] == nums[i - 1] && !used[i - 1]) {
                continue;
            }

            path.push_back(nums[i]);
            used[i] = true;
            backtrack(nums);
            used[i] = false;
            path.pop_back();
        }
    }
};

// 遞增子序列（特殊去重：不能排序）
class IncreasingSubsequences {
    vector<vector<int>> result;
    vector<int> path;

public:
    vector<vector<int>> findSubsequences(vector<int>& nums) {
        backtrack(nums, 0);
        return result;
    }

private:
    void backtrack(vector<int>& nums, int start) {
        if (path.size() >= 2) {
            result.push_back(path);
        }

        unordered_set<int> used; // 用集合記錄本層使用過的數字

        for (int i = start; i < nums.size(); i++) {
            // 不遞增或本層已使用，跳過
            if ((!path.empty() && nums[i] < path.back()) || used.count(nums[i])) {
                continue;
            }

            used.insert(nums[i]);
            path.push_back(nums[i]);
            backtrack(nums, i + 1);
            path.pop_back();
        }
    }
};
```

搜索問題通常使用 DFS 或 BFS 遍歷狀態空間，尋找目標狀態或最優解。

**DFS vs BFS**：
- **DFS**：深度優先，用堆疊（遞迴），空間複雜度低，不保證最短路徑
- **BFS**：廣度優先，用佇列，保證最短路徑，空間複雜度高

**C++ 模板**：

```cpp
// 單詞搜索（網格 DFS）
class WordSearch {
public:
    bool exist(vector<vector<char>>& board, string word) {
        int m = board.size(), n = board[0].size();

        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (dfs(board, word, i, j, 0)) {
                    return true;
                }
            }
        }
        return false;
    }

private:
    bool dfs(vector<vector<char>>& board, string& word, int i, int j, int k) {
        if (k == word.size()) {
            return true; // 找到完整單詞
        }

        if (i < 0 || i >= board.size() || j < 0 || j >= board[0].size() ||
            board[i][j] != word[k]) {
            return false;
        }

        char temp = board[i][j];
        board[i][j] = '#'; // 標記已訪問

        // 四個方向搜索
        bool found = dfs(board, word, i + 1, j, k + 1) ||
                     dfs(board, word, i - 1, j, k + 1) ||
                     dfs(board, word, i, j + 1, k + 1) ||
                     dfs(board, word, i, j - 1, k + 1);

        board[i][j] = temp; // 恢復
        return found;
    }
};

// 迷宮最短路徑（BFS）
class ShortestPath {
public:
    int shortestPath(vector<vector<int>>& grid, int sr, int sc, int tr, int tc) {
        if (grid[sr][sc] == 1 || grid[tr][tc] == 1) {
            return -1;
        }

        int m = grid.size(), n = grid[0].size();
        vector<vector<bool>> visited(m, vector<bool>(n, false));
        queue<tuple<int, int, int>> q; // {row, col, dist}

        q.push({sr, sc, 0});
        visited[sr][sc] = true;

        int dirs[4][2] = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};

        while (!q.empty()) {
            auto [r, c, dist] = q.front();
            q.pop();

            if (r == tr && c == tc) {
                return dist;
            }

            for (auto& dir : dirs) {
                int nr = r + dir[0];
                int nc = c + dir[1];

                if (nr >= 0 && nr < m && nc >= 0 && nc < n &&
                    !visited[nr][nc] && grid[nr][nc] == 0) {
                    visited[nr][nc] = true;
                    q.push({nr, nc, dist + 1});
                }
            }
        }

        return -1; // 無法到達
    }
};

// 島嶼數量（DFS 標記）
class NumIslands {
public:
    int numIslands(vector<vector<char>>& grid) {
        int m = grid.size(), n = grid[0].size();
        int count = 0;

        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (grid[i][j] == '1') {
                    dfs(grid, i, j);
                    count++;
                }
            }
        }
        return count;
    }

private:
    void dfs(vector<vector<char>>& grid, int i, int j) {
        if (i < 0 || i >= grid.size() || j < 0 || j >= grid[0].size() ||
            grid[i][j] != '1') {
            return;
        }

        grid[i][j] = '0'; // 標記已訪問

        dfs(grid, i + 1, j);
        dfs(grid, i - 1, j);
        dfs(grid, i, j + 1);
        dfs(grid, i, j - 1);
    }
};

// 八皇后（回溯搜索）
class NQueens {
    vector<vector<string>> result;

public:
    vector<vector<string>> solveNQueens(int n) {
        vector<string> board(n, string(n, '.'));
        backtrack(board, 0);
        return result;
    }

private:
    void backtrack(vector<string>& board, int row) {
        if (row == board.size()) {
            result.push_back(board);
            return;
        }

        for (int col = 0; col < board.size(); col++) {
            if (!isValid(board, row, col)) {
                continue;
            }

            board[row][col] = 'Q';
            backtrack(board, row + 1);
            board[row][col] = '.';
        }
    }

    bool isValid(vector<string>& board, int row, int col) {
        int n = board.size();

        // 檢查列
        for (int i = 0; i < row; i++) {
            if (board[i][col] == 'Q') {
                return false;
            }
        }

        // 檢查左上對角線
        for (int i = row - 1, j = col - 1; i >= 0 && j >= 0; i--, j--) {
            if (board[i][j] == 'Q') {
                return false;
            }
        }

        // 檢查右上對角線
        for (int i = row - 1, j = col + 1; i >= 0 && j < n; i--, j++) {
            if (board[i][j] == 'Q') {
                return false;
            }
        }

        return true;
    }
};
```

折半枚舉（Meet in the Middle）將搜索空間分成兩半，分別枚舉後合併結果，將時間複雜度從 $O(2^n)$ 降至 $O(2^{n/2})$。

**核心思想**：
- 將 n 個元素分成兩組，每組約 n/2 個
- 分別枚舉兩組的所有子集
- 合併兩組結果得到答案
- 時間複雜度：$O(2^{n/2} \cdot \log 2^{n/2})$ = $O(n \cdot 2^{n/2})$

**應用場景**：
- n 約為 40，暴力 $O(2^{40})$ 超時，折半後 $O(2^{20})$ 可行
- 子集和問題、背包問題等

**C++ 模板**：

```cpp
// 子集和問題：是否存在子集和為 target
bool subsetSum(vector<int>& nums, int target) {
    int n = nums.size();
    int mid = n / 2;

    // 枚舉前半部分的所有子集和
    unordered_set<int> first_half;
    for (int mask = 0; mask < (1 << mid); mask++) {
        int sum = 0;
        for (int i = 0; i < mid; i++) {
            if (mask & (1 << i)) {
                sum += nums[i];
            }
        }
        first_half.insert(sum);
    }

    // 枚舉後半部分，檢查是否與前半部分配對
    for (int mask = 0; mask < (1 << (n - mid)); mask++) {
        int sum = 0;
        for (int i = 0; i < n - mid; i++) {
            if (mask & (1 << i)) {
                sum += nums[mid + i];
            }
        }
        if (first_half.count(target - sum)) {
            return true;
        }
    }

    return false;
}

// 最接近目標的子集和
int closestSubsetSum(vector<int>& nums, int target) {
    int n = nums.size();
    int mid = n / 2;

    // 枚舉前半部分
    vector<int> first_half;
    for (int mask = 0; mask < (1 << mid); mask++) {
        int sum = 0;
        for (int i = 0; i < mid; i++) {
            if (mask & (1 << i)) {
                sum += nums[i];
            }
        }
        first_half.push_back(sum);
    }
    sort(first_half.begin(), first_half.end());

    // 枚舉後半部分
    int closest_sum = INT_MAX;
    int min_diff = INT_MAX;

    for (int mask = 0; mask < (1 << (n - mid)); mask++) {
        int sum = 0;
        for (int i = 0; i < n - mid; i++) {
            if (mask & (1 << i)) {
                sum += nums[mid + i];
            }
        }

        // 在前半部分中二分查找最接近 target - sum 的值
        int need = target - sum;
        auto it = lower_bound(first_half.begin(), first_half.end(), need);

        // 檢查 it 和 it-1
        if (it != first_half.end()) {
            int total = sum + *it;
            if (abs(total - target) < min_diff) {
                min_diff = abs(total - target);
                closest_sum = total;
            }
        }

        if (it != first_half.begin()) {
            it--;
            int total = sum + *it;
            if (abs(total - target) < min_diff) {
                min_diff = abs(total - target);
                closest_sum = total;
            }
        }
    }

    return closest_sum;
}

// 4sum II（四數之和為 0 的組數）
int fourSumCount(vector<int>& a, vector<int>& b, vector<int>& c, vector<int>& d) {
    unordered_map<int, int> sum_ab;

    // 枚舉 a 和 b 的所有組合
    for (int a : a) {
        for (int b : b) {
            sum_ab[a + b]++;
        }
    }

    int count = 0;

    // 枚舉 c 和 d，查找對應的 a+b
    for (int c : c) {
        for (int d : d) {
            int target = -(c + d);
            if (sum_ab.count(target)) {
                count += sum_ab[target];
            }
        }
    }

    return count;
}

// 分割等和子集（折半優化）
bool canPartition(vector<int>& nums) {
    int sum = accumulate(nums.begin(), nums.end(), 0);
    if (sum % 2 == 1) {
        return false;
    }

    int target = sum / 2;
    return subsetSum(nums, target);
}

// 最大 XOR 和（折半枚舉）
int maxXorSum(vector<int>& nums, int target) {
    int n = nums.size();
    int mid = n / 2;

    // 枚舉前半部分的所有 XOR 值
    unordered_set<int> first_half;
    for (int mask = 0; mask < (1 << mid); mask++) {
        int xor_val = 0;
        for (int i = 0; i < mid; i++) {
            if (mask & (1 << i)) {
                xor_val ^= nums[i];
            }
        }
        first_half.insert(xor_val);
    }

    // 枚舉後半部分，查找最大 XOR
    int max_xor = 0;
    for (int mask = 0; mask < (1 << (n - mid)); mask++) {
        int xor_val = 0;
        for (int i = 0; i < n - mid; i++) {
            if (mask & (1 << i)) {
                xor_val ^= nums[mid + i];
            }
        }

        // 在前半部分中找最大 XOR
        for (int val : first_half) {
            max_xor = max(max_xor, xor_val ^ val);
        }
    }

    return max_xor;
}
